import { useState, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import styles from "./Projects.module.css";
import Popup from './components/Popup';
import './components/Popup.css';
import GridItem from './components/GridItem'

import projects_lines from '../images/projects_lines.svg';
import foodieco1 from '../images/foodieco1.png';
import foodieco2 from '../images/foodieco2.png';
import lovethyhood from '../images/lovethyhood.png';
import healthyme from '../images/healthyme.png';
import readbetter from '../images/readbetter.png';
import ccc from '../images/ccc.png';
import bodyindepth1 from '../images/bodyindepth1.png';
import bodyindepth2 from '../images/bodyindepth2.png';

const Projects = () => {
  const navigate = useNavigate();

  const onHomeTextClick = useCallback(() => {
    navigate("/");
  }, [navigate]);

  const onLeadershipTextClick = useCallback(() => {
    navigate("/leadership");
  }, [navigate]);

  const onDevpostButtonClick = useCallback(() => {
    window.open("https://devpost.com/sooyeunleanne");
  }, []);

  const onButtonContainerClick = useCallback(() => {
    window.open("https://youtu.be/2BrVxchByck");
  }, []);

  const onButtonContainer1Click = useCallback(() => {
    window.open("https://www.youtube.com/watch?v=rGr_D0UZhUU");
  }, []);

  const onButtonClick = useCallback(() => {
    window.open("https://youtu.be/d77sW5xHxH4");
  }, []);

  const onButtonContainer2Click = useCallback(() => {
    window.open("https://youtu.be/BRFJ2iNiig0");
  }, []);

  const onButtonContainer3Click = useCallback(() => {
    window.open("https://youtu.be/BRFJ2iNiig0");
  }, []);

  const onHealThymeDemonstrationPicturClick = useCallback(() => {
    window.open("https://youtu.be/iKNFji-NY80");
  }, []);

  const onButtonContainer4Click = useCallback(() => {
    window.open("https://github.com/sooyeunleanne/Body-In-Depth");
  }, []);

  const [popupFoodieco, openFoodieco] = useState(false);
  const [popupLoveThyHood, openLoveThyHood] = useState(false);
  const [popupHealThyme, openHealThyme] = useState(false);
  const [popupReadBetter, openReadBetter] = useState(false);
  const [popupBodyInDepth, openBodyInDepth] = useState(false);
  const [popupStudySpace, openStudySpace] = useState(false);
  const [popupCCC, openCCC] = useState(false);

  return (
    <div className={styles.projects}>
      <div className={styles.header}>
        <div className={styles.headerBackground} />
        <div className={styles.home} onClick={onHomeTextClick}>
          Home
        </div>
        <div className={styles.projects1}>Projects</div>
        <div className={styles.leadership} onClick={onLeadershipTextClick}>
          Leadership
        </div>
      </div>

      <div className={styles.text}>
        <b className={styles.heading1}>Projects</b>
        <br/>
        <b className={styles.heading2}>Hackathons / Side Projects</b>
        <div className={styles.devpostButton} onClick={onDevpostButtonClick}>
          <div className={styles.devpostButtonChild} />
          <b className={styles.devpost} style ={{color: "white"}}>Devpost</b>
        </div>

        <div className = {styles.gridContainer} style = {{boxShadow: "10px 10px grey"}}>
          <GridItem children="Foodieco" trigger={popupFoodieco} setTrigger={openFoodieco}></GridItem>          
          <GridItem children="LoveThyHood" trigger={popupLoveThyHood} setTrigger={openLoveThyHood}></GridItem>
          <GridItem children="HealThyme" trigger={popupHealThyme} setTrigger={openHealThyme}></GridItem>
          <GridItem children="ReadBetter" trigger={popupReadBetter} setTrigger={openReadBetter}></GridItem>          
          <GridItem children="BodyInDepth" trigger={popupBodyInDepth} setTrigger={openBodyInDepth}></GridItem>
          <GridItem children="StudySpace" trigger={popupStudySpace} setTrigger={openStudySpace}></GridItem>
        </div>

        <Popup trigger={popupFoodieco} setTrigger={openFoodieco}><h3>FoodiEco</h3></Popup>
        <Popup trigger={popupLoveThyHood} setTrigger={openLoveThyHood}><h3>LoveThyHood</h3></Popup>
        <Popup trigger={popupHealThyme} setTrigger={openHealThyme}><h3>HealThyme</h3></Popup>
        <Popup trigger={popupReadBetter} setTrigger={openReadBetter}><h3>ReadBetter</h3></Popup>
        <Popup trigger={popupBodyInDepth} setTrigger={openBodyInDepth}><h3>BodyInDepth</h3></Popup>
        <Popup trigger={popupStudySpace} setTrigger={openStudySpace}><h3>StudySpace</h3></Popup>
      </div>
      <div>
        <b className={styles.heading2} style={{top: "53%"}}>Others</b>
        <div className = {styles.gridContainer} style = {{top: "55%", boxShadow: "10px 10px grey"}}>
          <GridItem children="Community Changemaker Challenge" trigger={popupCCC} setTrigger={openCCC}></GridItem>
        </div>

        <Popup trigger={popupCCC} setTrigger={openCCC}><h3>Community Changemaker Challenge</h3></Popup>
      </div>
    </div>
  );
};

export default Projects;
